import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path: sorts notes descending by updatedAt', () => {
    const notes = [
      { id: 1, updatedAt: '2023-01-01T10:00:00Z' },
      { id: 2, updatedAt: '2023-01-03T12:00:00Z' },
      { id: 3, updatedAt: '2023-01-02T08:30:00Z' },
    ];
    const result = sortNotesByUpdatedAt(notes);
    expect(result).toEqual([
      { id: 2, updatedAt: '2023-01-03T12:00:00Z' },
      { id: 3, updatedAt: '2023-01-02T08:30:00Z' },
      { id: 1, updatedAt: '2023-01-01T10:00:00Z' },
    ]);
  });

  it('should handle edge case: notes with same updatedAt retain original order', () => {
    const notes = [
      { id: 'a', updatedAt: '2023-05-05T09:00:00Z' },
      { id: 'b', updatedAt: '2023-05-05T09:00:00Z' },
      { id: 'c', updatedAt: '2023-04-01T12:00:00Z' },
    ];
    const result = sortNotesByUpdatedAt(notes);
    // The two notes with identical timestamps should stay in their input order
    expect(result).toEqual([
      { id: 'a', updatedAt: '2023-05-05T09:00:00Z' },
      { id: 'b', updatedAt: '2023-05-05T09:00:00Z' },
      { id: 'c', updatedAt: '2023-04-01T12:00:00Z' },
    ]);
  });

  it('should handle null/empty inputs: returns empty array for null, undefined, empty string, or 0', () => {
    // @ts-ignore - intentionally passing invalid types
    expect(sortNotesByUpdatedAt(null)).toEqual([]);
    // @ts-ignore
    expect(sortNotesByUpdatedAt(undefined)).toEqual([]);
    // @ts-ignore
    expect(sortNotesByUpdatedAt('')).toEqual([]);
    // @ts-ignore
    expect(sortNotesByUpdatedAt(0)).toEqual([]);
    // Proper empty array
    expect(sortNotesByUpdatedAt([])).toEqual([]);
  });
});

